input.newString:
// Per-variant sample size for a two-proportion test at 95% confidence,
// 80% power, to detect a relative lift of minLift% over the observed
// pooled conversion rate. Closed-form: n = 16 * p_bar * (1 - p_bar) / Δ²
// (Δ = absolute detectable difference = p_bar * minLift/100). Replaces the
// prior fixed 1000-floor / 31000-constant heuristic, which assumed p=0.5.
const pBar = pPool > 0 ? pPool : 0.5; // fall back to 0.5 only when no conversions yet
const delta = Math.max(0.0001, pBar * (minLift / 100)); // absolute MDE
const minSampleNeeded = Math.max(1, Math.ceil((16 * pBar * (1 - pBar)) / (delta * delta)));
const sampleAdequacy = Math.min(
  1,
  Math.min(data.variant_a_users, data.variant_b_users) / minSampleNeeded,
);

