/**
 * Logistic-regression scorer — the shared replacement for the hub's
 * fixed-weight heuristics (ICP, buyer intent, deal risk).
 *
 * Pure TS, no deps. Fits a binary logistic model by gradient descent with
 * L2 regularization, returns weights + diagnostics (calibration curve, AUC).
 * Consumers supply their own feature extractor + label query and call
 * fit/predict. Cold-start uses the existing heuristic as a prior; shrinkage
 * blends the fitted score with the prior until enough data arrives.
 *
 * See docs/HEURISTICS_AUDIT.md entries #1, #5, #6.
 */

export interface FitResult {
  weights: number[]; // per-feature coefficients
  intercept: number;
  n: number; // training rows
  epochs: number;
  converged: boolean;
  finalLoss: number;
}

export interface CalibrationBucket {
  bin: string; // e.g. "0.0-0.1"
  avgScore: number;
  avgLabel: number;
  count: number;
}

export interface CalibrationResult {
  buckets: CalibrationBucket[];
  auc: number;
  n: number;
}

const sigmoid = (z: number): number => 1 / (1 + Math.exp(-z));

/**
 * Fit a logistic-regression model by gradient descent with L2.
 *
 * @param X  feature matrix [n][d]
 * @param y  binary labels [n] (0 or 1)
 * @param opts learningRate, l2, maxEpochs, tol
 */
export function fit(
  X: number[][],
  y: number[],
  opts: { learningRate?: number; l2?: number; maxEpochs?: number; tol?: number } = {},
): FitResult {
  const lr = opts.learningRate ?? 0.1;
  const l2 = opts.l2 ?? 0.01;
  const maxEpochs = opts.maxEpochs ?? 2000;
  const tol = opts.tol ?? 1e-5;

  const n = X.length;
  const d = n > 0 ? X[0].length : 0;
  if (n === 0 || d === 0) {
    return { weights: new Array(d).fill(0), intercept: 0, n: 0, epochs: 0, converged: true, finalLoss: 0 };
  }

  let weights = new Array(d).fill(0);
  let intercept = 0;
  let prevLoss = Infinity;
  let converged = false;
  let epoch = 0;

  for (epoch = 1; epoch <= maxEpochs; epoch++) {
    const gradW = new Array(d).fill(0);
    let gradB = 0;
    let loss = 0;

    for (let i = 0; i < n; i++) {
      const z = intercept + dot(weights, X[i]);
      const p = sigmoid(z);
      const err = p - y[i];
      for (let j = 0; j < d; j++) gradW[j] += err * X[i][j];
      gradB += err;
      // log-loss (clamped to avoid log(0))
      const pc = Math.min(1 - 1e-12, Math.max(1e-12, p));
      loss += -y[i] * Math.log(pc) - (1 - y[i]) * Math.log(1 - pc);
    }

    // average + L2 penalty on weights
    for (let j = 0; j < d; j++) {
      gradW[j] = gradW[j] / n + l2 * weights[j];
      weights[j] -= lr * gradW[j];
    }
    intercept -= lr * (gradB / n);
    loss = loss / n + (l2 / 2) * dot(weights, weights);

    if (Math.abs(prevLoss - loss) < tol) {
      converged = true;
      break;
    }
    prevLoss = loss;
  }

  return { weights, intercept, n, epochs: epoch, converged, finalLoss: prevLoss };
}

/** Predict P(label=1) for a single feature vector. */
export function predict(model: Pick<FitResult, "weights" | "intercept">, x: number[]): number {
  return sigmoid(model.intercept + dot(model.weights, x));
}

/** Predict for many rows. */
export function predictMany(model: Pick<FitResult, "weights" | "intercept">, X: number[][]): number[] {
  return X.map((x) => predict(model, x));
}

/**
 * Calibration curve + AUC. The core "every heuristic ships with its own
 * measurement" primitive — bucket predicted scores into deciles, compare
 * average predicted vs average actual label per bucket.
 */
export function calibrate(scores: number[], labels: number[]): CalibrationResult {
  const n = scores.length;
  if (n === 0) return { buckets: [], auc: 0.5, n: 0 };

  const rows = scores.map((s, i) => ({ s, y: labels[i] })).sort((a, b) => a.s - b.s);
  const buckets: CalibrationBucket[] = [];
  const binSize = Math.max(1, Math.ceil(n / 10));
  for (let i = 0; i < n; i += binSize) {
    const slice = rows.slice(i, i + binSize);
    const avgScore = slice.reduce((s, r) => s + r.s, 0) / slice.length;
    const avgLabel = slice.reduce((s, r) => s + r.y, 0) / slice.length;
    const lo = (i / n).toFixed(1);
    const hi = (Math.min(n, i + binSize) / n).toFixed(1);
    buckets.push({ bin: `${lo}-${hi}`, avgScore, avgLabel, count: slice.length });
  }

  return { buckets, auc: auc(scores, labels), n };
}

/**
 * AUC via the Mann-Whitney U statistic. 0.5 = no signal, 1.0 = perfect
 * separation. The headline number to show beside every fitted score.
 */
export function auc(scores: number[], labels: number[]): number {
  const n = scores.length;
  if (n === 0) return 0.5;
  const pos = scores.filter((_, i) => labels[i] === 1);
  const neg = scores.filter((_, i) => labels[i] === 0);
  if (pos.length === 0 || neg.length === 0) return 0.5;

  let concordant = 0;
  let ties = 0;
  for (const p of pos) {
    for (const q of neg) {
      if (p > q) concordant++;
      else if (p === q) ties++;
    }
  }
  return (concordant + 0.5 * ties) / (pos.length * neg.length);
}

/**
 * Shrinkage blend toward a prior as cold-start. When n is small, trust the
 * prior (the legacy heuristic); as n grows past k, trust the fitted score.
 * blend = (n / (n + k)) * fitted + (k / (n + k)) * prior
 */
export function shrinkageBlend(fitted: number, prior: number, n: number, k: number): number {
  if (n <= 0) return prior;
  const w = n / (n + k);
  return w * fitted + (1 - w) * prior;
}

/** True if the model is trained on enough data to be trusted over a prior. */
export function isCalibrated(model: FitResult, minN: number): boolean {
  return model.n >= minN && model.converged;
}

// ─── helpers ──────────────────────────────────────────────────────────────
function dot(a: number[], b: number[]): number {
  let s = 0;
  for (let i = 0; i < a.length; i++) s += a[i] * b[i];
  return s;
}

/**
 * Standardize features to zero mean / unit variance before fitting, so
 * gradient descent converges and coefficients are comparable. Returns the
 * transform + its inverse applicator.
 */
export function standardize(X: number[][]): {
  Xs: number[][];
  mean: number[];
  std: number[];
  apply: (x: number[]) => number[];
} {
  const n = X.length;
  const d = n > 0 ? X[0].length : 0;
  const mean = new Array(d).fill(0);
  const std = new Array(d).fill(0);
  for (const row of X) for (let j = 0; j < d; j++) mean[j] += row[j];
  for (let j = 0; j < d; j++) mean[j] /= Math.max(1, n);
  for (const row of X) for (let j = 0; j < d; j++) std[j] += (row[j] - mean[j]) ** 2;
  for (let j = 0; j < d; j++) std[j] = Math.sqrt(std[j] / Math.max(1, n)) || 1;
  const Xs = X.map((row) => row.map((v, j) => (v - mean[j]) / std[j]));
  return { Xs, mean, std, apply: (x: number[]) => x.map((v, j) => (v - mean[j]) / std[j]) };
}

