/**
 * Score a single contact against the ICP.
 *
 * Uses a logistic-regression model fit on closed-won / closed-lost deals when
 * enough data exists; falls back to the legacy fixed-weight prior and
 * shrinkage-blends the two as data grows. The model's AUC is returned with
 * every score so the UI can show whether the score is calibrated.
 */
export function scoreContact(contactId: string): ContactScore {
  const profile = trainICP();
  const contact = db.prepare(`
    SELECT id, name, email, industry, company, title FROM contacts WHERE id = ?
  `).get(contactId) as { id: string; name: string; email: string; industry: string; company: string; title: string } | undefined;

  if (!contact) {
    return {
      contactId,
      score: 0,
      grade: "F",
      fitSignals: [],
      gapSignals: ["Contact not found"],
      recommendation: "Contact does not exist.",
      calibration: { model: "prior", n: 0, auc: 0.5 },
    };
  }

  const fitSignals: string[] = [];
  const gapSignals: string[] = [];

  // Pull the contact's historical deal value for the prior + as a model feature.
  const contactDeals = db.prepare(`
    SELECT value, stage FROM deals WHERE contact_id = ?
  `).all(contactId) as { value: number; stage: string }[];
  const avgContactDeal = contactDeals.length > 0
    ? contactDeals.reduce((s, d) => s + d.value, 0) / contactDeals.length
    : 0;

  // ── Prior score (the legacy fixed-weight heuristic, kept as cold-start) ──
  let prior = 0.3;
  if (contact.industry && profile.topIndustries.length > 0) {
    const match = profile.topIndustries.find((i) => i.industry === contact.industry);
    if (match) {
      prior += match.weight * 0.4;
      fitSignals.push(`Industry "${contact.industry}" matches ICP (${(match.weight * 100).toFixed(0)}% of won deals)`);
      const winRate = profile.winRateByIndustry[contact.industry];
      if (winRate !== undefined && winRate > 0.5) {
        prior += 0.1;
        fitSignals.push(`High win rate in ${contact.industry} (${(winRate * 100).toFixed(0)}%)`);
      }
    } else {
      gapSignals.push(`Industry "${contact.industry}" not in top ICP industries`);
    }
  }
  if (avgContactDeal > 0 && profile.avgDealValue > 0) {
    const ratio = avgContactDeal / profile.avgDealValue;
    if (ratio > 0.8) {
      prior += 0.15;
      fitSignals.push(`Deal value ($${avgContactDeal.toLocaleString()}) aligns with ICP average ($${profile.avgDealValue.toLocaleString()})`);
    } else if (ratio < 0.3) {
      prior -= 0.1;
      gapSignals.push(`Deal value ($${avgContactDeal.toLocaleString()}) below ICP average ($${profile.avgDealValue.toLocaleString()})`);
    }
  }
  if (contact.title && SENIOR_TITLES.test(contact.title)) {
    prior += 0.1;
    fitSignals.push(`Senior title: ${contact.title} (decision-maker)`);
  }
  if (contact.company) {
    prior += 0.05;
    fitSignals.push(`Company identified: ${contact.company}`);
  } else {
    gapSignals.push("No company associated");
  }
  prior = Math.max(0, Math.min(1, prior));

  // ── Fitted score (logistic regression on historical deal outcomes) ──
  trainICPModel();
  let fitted = prior;
  let modelN = 0;
  let auc = 0.5;
  let mode: "fitted" | "prior" | "blended" = "prior";
  if (_icpModel) {
    const features = extractFeatures(contact, avgContactDeal, _icpModel.industries);
    fitted = ml.predict(_icpModel.model, _icpModel.apply(features));
    modelN = _icpModel.model.n;
    auc = _icpModel.auc;
    mode = modelN >= MIN_FITTED_N ? "fitted" : "blended";
  }

  const score = Math.max(0, Math.min(1, ml.shrinkageBlend(fitted, prior, modelN, SHRINKAGE_K)));

  const grade = score >= 0.8 ? "A" : score >= 0.6 ? "B" : score >= 0.4 ? "C" : "D";
  const recommendation =
    score >= 0.7 ? "Prioritize — strong ICP fit. Route to outreach." :
    score >= 0.5 ? "Nurture — moderate fit. Keep in sequence." :
    "Low priority — weak ICP fit. Reconsider or deprioritize.";

  return {
    contactId,
    score,
    grade,
    fitSignals,
    gapSignals,
    recommendation,
    calibration: { model: mode, n: modelN, auc },
  };
}

/**
 * Feature vector for the logistic model. One-hot industry (over the top-N
 * ICP industries) + log(deal value) + title seniority (ordinal) + has company.
 */
function extractFeatures(
  contact: { industry: string; company: string; title: string },
  avgContactDeal: number,
  industries: string[],
): number[] {
  const feats: number[] = [];
  for (const ind of industries) feats.push(contact.industry === ind ? 1 : 0);
  feats.push(Math.log1p(Math.max(0, avgContactDeal)));
  feats.push(contact.title && SENIOR_TITLES.test(contact.title) ? 1 : 0);
  feats.push(contact.company ? 1 : 0);
  return feats;
}

/**
 * Fit (and cache) the logistic-regression ICP model on historical deal
 * outcomes. Features: one-hot industry, log(deal value), seniority, has
 * company. Label: 1 if any of the contact's deals is closed-won, else 0.
 */
function trainICPModel(): void {
  if (_icpModel) return;

  const rows = db.prepare(`
    SELECT c.id, c.industry, c.company, c.title,
           AVG(d.value) AS avg_value,
           MAX(CASE WHEN d.stage IN ('closed-won','won') THEN 1 ELSE 0 END) AS won
    FROM contacts c
    LEFT JOIN deals d ON d.contact_id = c.id
    GROUP BY c.id
    HAVING COUNT(d.id) > 0
  `).all() as { id: string; industry: string; company: string; title: string; avg_value: number; won: number }[];

  if (rows.length === 0) return;

  // Top industries by frequency (one-hot only the top 10 to keep dimensionality sane)
  const industryCounts: Record<string, number> = {};
  for (const r of rows) if (r.industry) industryCounts[r.industry] = (industryCounts[r.industry] || 0) + 1;
  const industries = Object.entries(industryCounts)
    .sort(([, a], [, b]) => b - a)
    .slice(0, 10)
    .map(([i]) => i);

  const X: number[][] = [];
  const y: number[] = [];
  for (const r of rows) {
    X.push([
      ...industries.map((i) => (r.industry === i ? 1 : 0)),
      Math.log1p(Math.max(0, r.avg_value || 0)),
      r.title && SENIOR_TITLES.test(r.title) ? 1 : 0,
      r.company ? 1 : 0,
    ]);
    y.push(r.won);
  }

  const { Xs, apply } = ml.standardize(X);
  const model = ml.fit(Xs, y);
  const scores = ml.predictMany(model, Xs);
  const calibration = ml.calibrate(scores, y);

  _icpModel = { model, industries, apply, auc: calibration.auc };
}

