 */
export function scoreContact(contactId: string): ContactScore {
  const profile = trainICP();
  const contact = db.prepare(`
    SELECT id, name, email, industry, company, title FROM contacts WHERE id = ?
  `).get(contactId) as { id: string; name: string; email: string; industry: string; company: string; title: string } | undefined;

  if (!contact) {
    return {
      contactId,
      score: 0,
      grade: "F",
      fitSignals: [],
      gapSignals: ["Contact not found"],
      recommendation: "Contact does not exist.",
    };
  }

  let score = 0.3; // base score
  const fitSignals: string[] = [];
  const gapSignals: string[] = [];

  // 1. Industry match (highest weight)
  if (contact.industry && profile.topIndustries.length > 0) {
    const match = profile.topIndustries.find((i) => i.industry === contact.industry);
    if (match) {
      score += match.weight * 0.4;
      fitSignals.push(`Industry "${contact.industry}" matches ICP (${(match.weight * 100).toFixed(0)}% of won deals)`);
      const winRate = profile.winRateByIndustry[contact.industry];
      if (winRate !== undefined && winRate > 0.5) {
        score += 0.1;
        fitSignals.push(`High win rate in ${contact.industry} (${(winRate * 100).toFixed(0)}%)`);
      }
    } else {
      gapSignals.push(`Industry "${contact.industry}" not in top ICP industries`);
    }
  }

  // 2. Deal value potential (if the contact has deals, compare to avg)
  const contactDeals = db.prepare(`
    SELECT value, stage FROM deals WHERE contact_id = ?
  `).all(contactId) as { value: number; stage: string }[];

  if (contactDeals.length > 0) {
    const avgContactDeal = contactDeals.reduce((s, d) => s + d.value, 0) / contactDeals.length;
    if (profile.avgDealValue > 0) {
      const ratio = avgContactDeal / profile.avgDealValue;
      if (ratio > 0.8) {
        score += 0.15;
        fitSignals.push(`Deal value ($${avgContactDeal.toLocaleString()}) aligns with ICP average ($${profile.avgDealValue.toLocaleString()})`);
      } else if (ratio < 0.3) {
        score -= 0.1;
        gapSignals.push(`Deal value ($${avgContactDeal.toLocaleString()}) below ICP average ($${profile.avgDealValue.toLocaleString()})`);
      }
    }
  }

  // 3. Title seniority (decision-makers score higher)
  if (contact.title) {
    const seniorTitles = /\b(CEO|CTO|CMO|CFO|founder|owner|vp|vice president|director|head of)\b/i;
    if (seniorTitles.test(contact.title)) {
      score += 0.1;
      fitSignals.push(`Senior title: ${contact.title} (decision-maker)`);
    }
  }

  // 4. Has company (B2B signal)
  if (contact.company) {
    score += 0.05;
    fitSignals.push(`Company identified: ${contact.company}`);
  } else {
    gapSignals.push("No company associated");
  }

  // Clamp 0-1
  score = Math.max(0, Math.min(1, score));

  const grade = score >= 0.8 ? "A" : score >= 0.6 ? "B" : score >= 0.4 ? "C" : "D";
  const recommendation =
    score >= 0.7 ? "Prioritize — strong ICP fit. Route to outreach." :
    score >= 0.5 ? "Nurture — moderate fit. Keep in sequence." :
    "Low priority — weak ICP fit. Reconsider or deprioritize.";

  return { contactId, score, grade, fitSignals, gapSignals, recommendation };
}

