export function getICPSummary(): string {
  const profile = trainICP();
  trainICPModel();
  if (profile.totalTrained === 0) {
    return "ICP: No training data yet (no closed-won deals). Score is a prior — uncalibrated until deals close.";
  }
  const parts = [
    `ICP (trained on ${profile.totalTrained} won deals):`,
    `- Average deal value: $${profile.avgDealValue.toLocaleString()}`,
    `- Top industries: ${profile.topIndustries.map((i) => `${i.industry} (${(i.weight * 100).toFixed(0)}%)`).join(", ")}`,
  ];
  const topWinRates = Object.entries(profile.winRateByIndustry)
    .filter(([, r]) => r > 0.5)
    .sort(([, a], [, b]) => b - a)
    .slice(0, 3);
  if (topWinRates.length > 0) {
    parts.push(`- High win-rate industries: ${topWinRates.map(([i, r]) => `${i} (${(r * 100).toFixed(0)}%)`).join(", ")}`);
  }
  if (_icpModel) {
    const mode = _icpModel.model.n >= MIN_FITTED_N ? "fitted" : "blended (prior + fitted)";
    parts.push(`- Model: logistic regression, n=${_icpModel.model.n}, AUC=${_icpModel.auc.toFixed(2)} (${mode})`);
  }
  return parts.join("\n");
}

