import * as ml from "@/lib/ml/logistic";

export interface IntentSignal {
  contactId: string;
  signalType: "page_view" | "form_fill" | "pricing_view" | "demo_request" | "career_view" | "email_open" | "ad_click" | "search";
  signalValue: string;      // e.g., "/pricing", "demo form submitted", "opened campaign email"
  weight: number;           // 0-1 (how strong this signal is)
  timestamp: number;
  source?: string;          // "website", "email", "ads", "organic"
  utm?: { source?: string; medium?: string; campaign?: string };
}

export interface IntentScore {
  contactId: string;
  score: number;            // 0-1
  level: "cold" | "warm" | "hot" | "ready";
  signals: IntentSignal[];
  topSignals: string[];
  recommendedAction: string;
  lastActivity: number;
  /** Calibration metadata — every score ships with its own measurement. */
  calibration: { model: "fitted" | "prior" | "blended"; n: number; auc: number };
}

const SIGNAL_TYPES: IntentSignal["signalType"][] = [
  "page_view", "form_fill", "pricing_view", "demo_request",
  "career_view", "email_open", "ad_click", "search",
];

// Prior weights (the legacy fixed table). Kept as cold-start prior and
// shrinkage-blended out as the fitted model sees more won/lost outcomes.
