  pricing_view: 0.30,
  demo_request: 0.35,
  form_fill: 0.20,
  page_view: 0.05,
  career_view: 0.02,
  email_open: 0.03,
  ad_click: 0.08,
  search: 0.06,
};

const MIN_FITTED_N = 200;
const SHRINKAGE_K = 400;

