/**
 * Calculate the intent score for a contact.
 *
 * Uses a logistic-regression model fit on (signals → won-deal-within-30d)
 * when enough data exists; falls back to the legacy signal-weight prior and
 * shrinkage-blends. Returns AUC + n so the UI can show calibration.
 */
export function scoreIntent(contactId: string): IntentScore {
  // Get signals from the last 30 days
  const thirtyDaysAgo = now() - 30 * 24 * 60 * 60 * 1000;
  const signals = db.prepare(`
    SELECT * FROM intent_signals WHERE contact_id = ? AND timestamp > ? ORDER BY timestamp DESC
  `).all(contactId, thirtyDaysAgo) as (IntentSignal & { utm: string })[];

  if (signals.length === 0) {
    return {
      contactId,
      score: 0,
      level: "cold",
      signals: [],
      topSignals: [],
      recommendedAction: "No recent intent signals. Nurture with content + retargeting.",
      lastActivity: 0,
      calibration: { model: "prior", n: 0, auc: 0.5 },
    };
  }

  // ── Prior score (legacy weighted sum with diminishing returns + recency boost) ──
  const signalTypeCounts: Record<string, number> = {};
  let prior = 0;
  for (const s of signals) {
    const count = (signalTypeCounts[s.signalType] || 0) + 1;
    signalTypeCounts[s.signalType] = count;
    prior += s.weight / Math.sqrt(count);
  }
  const sevenDaysAgo = now() - 7 * 24 * 60 * 60 * 1000;
  if (signals.some((s) => s.timestamp > sevenDaysAgo)) prior *= 1.2;
  prior = Math.max(0, Math.min(1, prior));

  // ── Fitted score (logistic regression on signals → won-within-30d) ──
  const model = trainIntentModel();
  let fitted = prior;
  let modelN = 0;
  let auc = 0.5;
  let mode: "fitted" | "prior" | "blended" = "prior";
  if (model) {
    const feats = extractIntentFeatures(signals);
    fitted = ml.predict(model.model, model.apply(feats));
    modelN = model.model.n;
    auc = model.auc;
    mode = modelN >= MIN_FITTED_N ? "fitted" : "blended";
  }

  const score = Math.max(0, Math.min(1, ml.shrinkageBlend(fitted, prior, modelN, SHRINKAGE_K)));

  const level = score >= 0.7 ? "ready" : score >= 0.4 ? "hot" : score >= 0.2 ? "warm" : "cold";

  // Top signals (the 3 strongest)
  const topSignals = signals
    .slice()
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 3)
    .map((s) => `${s.signalType.replace(/_/g, " ")}: ${s.signalValue}`);

  const recommendedAction =
    level === "ready" ? "PRIORITIZE — contact is ready to buy. Route to sales immediately." :
    level === "hot" ? "FOLLOW UP — contact is highly engaged. Send a personalized offer + book a call." :
    level === "warm" ? "NURTURE — contact is warming up. Send targeted content + retargeting ads." :
    "NURTURE — contact is cold. Keep in the content sequence + monitor for signals";

  const lastActivity = Math.max(...signals.map((s) => s.timestamp));

  return { contactId, score, level, signals: signals.slice(0, 10), topSignals, recommendedAction, lastActivity, calibration: { model: mode, n: modelN, auc } };
}

/**
 * Feature vector for the intent logistic model. For each signal type:
 * log(1 + count) in the 30d window. Plus days since last signal (recency).
 */
function extractIntentFeatures(signals: IntentSignal[]): number[] {
  const counts: Record<string, number> = {};
  for (const s of signals) counts[s.signalType] = (counts[s.signalType] || 0) + 1;
  const feats = SIGNAL_TYPES.map((t) => Math.log1p(counts[t] || 0));
  const lastTs = signals.length > 0 ? Math.max(...signals.map((s) => s.timestamp)) : 0;
  feats.push(Math.log1p(Math.max(0, (now() - lastTs) / 86400000))); // days since last signal
  return feats;
}

let _intentModel: { model: ml.FitResult; apply: (x: number[]) => number[]; auc: number } | null = null;

/**
 * Fit (and cache) the intent logistic model. Each training row = one contact's
 * 30-day signal window. Label = 1 if the contact closed a won deal within 30d
 * of the window end, else 0.
 */
function trainIntentModel(): { model: ml.FitResult; apply: (x: number[]) => number[]; auc: number } | null {
  if (_intentModel) return _intentModel;

  // Contacts that have any signals
  const contacts = db.prepare(`
    SELECT DISTINCT contact_id FROM intent_signals
  `).all() as { contact_id: string }[];
  if (contacts.length === 0) return null;

  const t = now();
  const thirtyDaysMs = 30 * 24 * 60 * 60 * 1000;
  const X: number[][] = [];
  const y: number[] = [];

  for (const { contact_id } of contacts) {
    const sigs = db.prepare(`
      SELECT signal_type, timestamp FROM intent_signals
      WHERE contact_id = ? AND timestamp > ?
      ORDER BY timestamp DESC
    `).all(contact_id, t - thirtyDaysMs) as { signal_type: string; timestamp: number }[];

    if (sigs.length === 0) continue;

    const won = db.prepare(`
      SELECT 1 FROM deals
      WHERE contact_id = ? AND stage IN ('closed-won','won')
        AND created_at > ? AND created_at <= ?
      LIMIT 1
    `).get(contact_id, t - thirtyDaysMs, t) as { 1: number } | undefined;

    const feats = extractIntentFeatures(sigs as unknown as IntentSignal[]);
    X.push(feats);
    y.push(won ? 1 : 0);
  }

  if (X.length === 0) return null;
  const { Xs, apply } = ml.standardize(X);
  const model = ml.fit(Xs, y);
  const scores = ml.predictMany(model, Xs);
  const calibration = ml.calibrate(scores, y);
  _intentModel = { model, apply, auc: calibration.auc };
  return _intentModel;
}

