      level: "cold",
      signals: [],
      topSignals: [],
      recommendedAction: "No recent intent signals. Nurture with content + retargeting.",
      lastActivity: 0,
    };
  }

  // Score: sum of signal weights, with diminishing returns for repeated signals
  const signalTypeCounts: Record<string, number> = {};
  let score = 0;
  for (const s of signals) {
    const count = (signalTypeCounts[s.signalType] || 0) + 1;
    signalTypeCounts[s.signalType] = count;
    // Diminishing returns: each repeated signal of the same type is worth less
    const diminishingWeight = s.weight / Math.sqrt(count);
    score += diminishingWeight;
  }

  // Recency boost: signals in the last 7 days get a 1.5x boost
  const sevenDaysAgo = now() - 7 * 24 * 60 * 60 * 1000;
  const recentSignals = signals.filter((s) => s.timestamp > sevenDaysAgo);
  if (recentSignals.length > 0) {
    score *= 1.2; // 20% boost for recent activity
  }

  // Clamp 0-1
  score = Math.max(0, Math.min(1, score));

  const level = score >= 0.7 ? "ready" : score >= 0.4 ? "hot" : score >= 0.2 ? "warm" : "cold";

  // Top signals (the 3 strongest)
  const topSignals = signals
    .slice()
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 3)
    .map((s) => `${s.signalType.replace(/_/g, " ")}: ${s.signalValue}`);

