/**
 * Score a deal's risk. Uses a logistic-regression model fit on
 * (deal features → closed-lost-within-60d) when enough data exists; falls
 * back to the legacy fixed-increment prior and shrinkage-blends. The risk
 * *factors* (the boolean flags) are still emitted so the recommended actions
 * stay keyed off concrete evidence — the model only replaces the additive
 * risk score, not the diagnostic.
 */
export function scoreDealRisk(dealId: string): DealRiskScore {
  const deal = db.prepare(`
    SELECT id, title, value, stage, contact_id, created_at, close_date AS expected_close_date
    FROM deals WHERE id = ?
  `).get(dealId) as { id: string; title: string; value: number; stage: string; contact_id: string; created_at: number; expected_close_date: number } | undefined;

  if (!deal) {
    return {
      dealId,
      risk: 1,
      riskLevel: "critical",
      riskFactors: [{ factor: "Deal not found", evidence: "No deal with this ID", severity: 1 }],
      recommendedActions: [],
      summary: "Deal not found.",
