  const daysInStage = Math.floor((t - deal.created_at) / (1000 * 60 * 60 * 24));
  let stalledSeverity = 0;
  if (daysInStage > 60 && deal.stage !== "closed-won" && deal.stage !== "closed-lost") {
    stalledSeverity = 0.25;
    riskFactors.push({ factor: "Stalled in stage", evidence: `Deal has been in "${deal.stage}" for ${daysInStage} days (>60 days = stalled).`, severity: 0.25 });
    actions.push({ action: "Follow up with the contact — re-qualify or move to next stage.", owner: "Sales", urgency: "high" });
  } else if (daysInStage > 30) {
    stalledSeverity = 0.1;
    riskFactors.push({ factor: "Slow progression", evidence: `${daysInStage} days in "${deal.stage}" (>30 days).`, severity: 0.1 });
    actions.push({ action: "Check in with the contact — any blockers?", owner: "Sales", urgency: "medium" });
  }

  let lastActivity: { last: number } | undefined;
  try {
    lastActivity = db.prepare(`SELECT MAX(created_at) as last FROM deal_notes WHERE deal_id = ?`).get(dealId) as { last: number } | undefined;
