  if (daysSinceActivity > 14) {
    riskFactors.push({ factor: "No recent activity", evidence: `${daysSinceActivity === 999 ? "Never" : `${daysSinceActivity} days since last note`} — deal is going cold.`, severity: 0.2 });
    actions.push({ action: "Add a note + reach out to the contact today.", owner: "Sales", urgency: "high" });
  }

  const isOverdue = !!(deal.expected_close_date && deal.expected_close_date < t && deal.stage !== "closed-won");
  if (isOverdue) {
    const daysOverdue = Math.floor((t - deal.expected_close_date) / (1000 * 60 * 60 * 24));
    riskFactors.push({ factor: "Overdue close date", evidence: `Expected close date passed ${daysOverdue} days ago.`, severity: 0.2 });
    actions.push({ action: "Update the close date or move to closed-lost.", owner: "Sales", urgency: "high" });
  }

  const isHighValueEarly = deal.value > 50000 && EARLY_STAGES.includes(deal.stage);
  if (isHighValueEarly) {
    riskFactors.push({ factor: "High value in early stage", evidence: `$${deal.value.toLocaleString()} deal in "${deal.stage}" — high-value deals in early stages are volatile.`, severity: 0.15 });
    actions.push({ action: "Accelerate — move to a later stage or schedule a demo.", owner: "Senior Partner", urgency: "medium" });
