    ? `CRITICAL: ${riskFactors.length} risk factors. Immediate action required.`
    : riskLevel === "at-risk"
    ? `AT RISK: ${riskFactors.length} risk factors. Follow up this week.`
    : riskLevel === "watch"
    ? `WATCH: ${riskFactors.length} minor risk factors. Monitor.`
    : `SAFE: No significant risk factors.`;

  return { dealId, risk, riskLevel, riskFactors, recommendedActions: actions, summary, calibration: { model: mode, n: modelN, auc } };
