/**
 * Feature vector: log(1+days_in_stage), days_since_last_note, is_overdue,
 * log(value) × is_early_stage, has_contact.
 */
function extractDealFeatures(
  deal: { value: number; stage: string; contact_id: string; expected_close_date: number; created_at: number },
  daysSinceActivity: number,
  daysInStage: number,
  t: number,
): number[] {
  const isOverdue = !!(deal.expected_close_date && deal.expected_close_date < t && deal.stage !== "closed-won");
  return [
    Math.log1p(daysInStage),
    Math.log1p(daysSinceActivity === 999 ? 999 : daysSinceActivity),
    isOverdue ? 1 : 0,
    Math.log1p(Math.max(0, deal.value)) * (EARLY_STAGES.includes(deal.stage) ? 1 : 0),
    deal.contact_id ? 1 : 0,
  ];
}

let _dealRiskModel: { model: ml.FitResult; apply: (x: number[]) => number[]; auc: number } | null = null;

/**
 * Fit (and cache) the deal-risk logistic model on historical deals. Label =
 * 1 if the deal ended closed-lost within 60d of the snapshot, else 0.
 */
function trainDealRiskModel(): { model: ml.FitResult; apply: (x: number[]) => number[]; auc: number } | null {
  if (_dealRiskModel) return _dealRiskModel;

  const deals = db.prepare(`
    SELECT id, value, stage, contact_id, created_at, close_date AS expected_close_date,
           (SELECT MAX(created_at) FROM deal_notes WHERE deal_id = deals.id) AS last_note_at
    FROM deals
    WHERE stage IN ('closed-won','closed-lost','won','lost')
  `).all() as { id: string; value: number; stage: string; contact_id: string; created_at: number; expected_close_date: number; last_note_at: number | null }[];

  if (deals.length === 0) return null;

  const t = now();
  const X: number[][] = [];
  const y: number[] = [];
  for (const d of deals) {
    const daysInStage = Math.floor((t - d.created_at) / (1000 * 60 * 60 * 24));
    const daysSinceActivity = d.last_note_at ? Math.floor((t - d.last_note_at) / (1000 * 60 * 60 * 24)) : 999;
    X.push(extractDealFeatures(d, daysSinceActivity, daysInStage, t));
    y.push(["closed-lost", "lost"].includes(d.stage) ? 1 : 0);
  }

  const { Xs, apply } = ml.standardize(X);
  const model = ml.fit(Xs, y);
  const scores = ml.predictMany(model, Xs);
  const calibration = ml.calibrate(scores, y);
  _dealRiskModel = { model, apply, auc: calibration.auc };
  return _dealRiskModel;
}

