/**
 * Score a deal's risk based on stage, timeline, contact, and activity.
 */
export function scoreDealRisk(dealId: string): DealRiskScore {
  const deal = db.prepare(`
    SELECT id, title, value, stage, contact_id, created_at, close_date AS expected_close_date
    FROM deals WHERE id = ?
  `).get(dealId) as { id: string; title: string; value: number; stage: string; contact_id: string; created_at: number; expected_close_date: number } | undefined;

  if (!deal) {
    return {
      dealId,
      risk: 1,
      riskLevel: "critical",
      riskFactors: [{ factor: "Deal not found", evidence: "No deal with this ID", severity: 1 }],
      recommendedActions: [],
      summary: "Deal not found.",
    };
  }

  let risk = 0;
  const riskFactors: DealRiskScore["riskFactors"] = [];
  const actions: DealRiskScore["recommendedActions"] = [];
  const t = now();

  // 1. Stalled in stage (been in the same stage too long)
  const daysInStage = Math.floor((t - deal.created_at) / (1000 * 60 * 60 * 24));
  if (daysInStage > 60 && deal.stage !== "closed-won" && deal.stage !== "closed-lost") {
    risk += 0.25;
    riskFactors.push({
      factor: "Stalled in stage",
      evidence: `Deal has been in "${deal.stage}" for ${daysInStage} days (>60 days = stalled).`,
      severity: 0.25,
    });
    actions.push({ action: "Follow up with the contact — re-qualify or move to next stage.", owner: "Sales", urgency: "high" });
  } else if (daysInStage > 30) {
    risk += 0.1;
    riskFactors.push({
      factor: "Slow progression",
      evidence: `${daysInStage} days in "${deal.stage}" (>30 days).`,
      severity: 0.1,
    });
    actions.push({ action: "Check in with the contact — any blockers?", owner: "Sales", urgency: "medium" });
  }

  // 2. No recent activity (no notes, no contact log in 14 days)
  let lastActivity: { last: number } | undefined;
  try {
    lastActivity = db.prepare(`
      SELECT MAX(created_at) as last FROM deal_notes WHERE deal_id = ?
    `).get(dealId) as { last: number } | undefined;
  } catch {
    lastActivity = { last: t };
  }
  const daysSinceActivity = lastActivity?.last ? Math.floor((t - lastActivity.last) / (1000 * 60 * 60 * 24)) : 999;
  if (daysSinceActivity > 14) {
    risk += 0.2;
    riskFactors.push({
      factor: "No recent activity",
      evidence: `${daysSinceActivity === 999 ? "Never" : `${daysSinceActivity} days since last note`} — deal is going cold.`,
      severity: 0.2,
    });
    actions.push({ action: "Add a note + reach out to the contact today.", owner: "Sales", urgency: "high" });
  }

  // 3. Expected close date passed (overdue)
  if (deal.expected_close_date && deal.expected_close_date < t && deal.stage !== "closed-won") {
    risk += 0.2;
    const daysOverdue = Math.floor((t - deal.expected_close_date) / (1000 * 60 * 60 * 24));
    riskFactors.push({
      factor: "Overdue close date",
      evidence: `Expected close date passed ${daysOverdue} days ago.`,
      severity: 0.2,
    });
    actions.push({ action: "Update the close date or move to closed-lost.", owner: "Sales", urgency: "high" });
  }

  // 4. High value + early stage (risky — big deals in early stages are volatile)
  if (deal.value > 50000 && ["lead", "qualified", "contacted"].includes(deal.stage)) {
    risk += 0.15;
    riskFactors.push({
      factor: "High value in early stage",
      evidence: `$${deal.value.toLocaleString()} deal in "${deal.stage}" — high-value deals in early stages are volatile.`,
      severity: 0.15,
    });
    actions.push({ action: "Accelerate — move to a later stage or schedule a demo.", owner: "Senior Partner", urgency: "medium" });
  }

  // 5. No contact associated
  if (!deal.contact_id) {
    risk += 0.1;
    riskFactors.push({
      factor: "No contact linked",
      evidence: "Deal has no associated contact — can't follow up.",
      severity: 0.1,
    });
    actions.push({ action: "Link a contact to this deal.", owner: "Sales", urgency: "low" });
  }

  // Clamp 0-1
  risk = Math.max(0, Math.min(1, risk));

  const riskLevel = risk >= 0.6 ? "critical" : risk >= 0.4 ? "at-risk" : risk >= 0.2 ? "watch" : "safe";
  const summary = riskLevel === "critical"
    ? `CRITICAL: ${riskFactors.length} risk factors. Immediate action required.`
    : riskLevel === "at-risk"
    ? `AT RISK: ${riskFactors.length} risk factors. Follow up this week.`
    : riskLevel === "watch"
    ? `WATCH: ${riskFactors.length} minor risk factors. Monitor.`
    : `SAFE: No significant risk factors.`;

  return { dealId, risk, riskLevel, riskFactors, recommendedActions: actions, summary };
}

