function getConversionRateByChannel(): Record<string, number> {
  // Legacy per-channel conversion-rate prior. Retained for the channel_rate
  // fallback path and as a sanity check; the data_driven model now uses the
  // Markov removal-effect below instead.
  const rows = db
    .prepare(
      `
    SELECT t.channel,
           COUNT(DISTINCT t.id) AS touches,
           COUNT(DISTINCT CASE WHEN d.stage = 'won' THEN d.id END) AS won_deals
    FROM touchpoints t
    LEFT JOIN deals d ON d.id = t.deal_id
    GROUP BY t.channel
  `,
    )
    .all() as Record<string, unknown>[];
  const out: Record<string, number> = {};
  for (const r of rows) {
    out[r.channel] = r.touches > 0 ? r.won_deals / r.touches : 0;
  }
  return out;
}

/**
 * Build the Markov transition graph from all deal touchpoint paths.
 * States: "start", each channel, "won", "lost". Edges: start→first channel,
 * channel[i]→channel[i+1], last channel→{won|lost} (from the deal's stage).
 * Returns the transition counts + the channel set.
 */
function buildMarkovGraph(): {
  transitions: Map<string, Map<string, number>>;
  channels: string[];
} {
  const transitions = new Map<string, Map<string, number>>();
  const addEdge = (from: string, to: string) => {
    if (!transitions.has(from)) transitions.set(from, new Map());
    const m = transitions.get(from)!;
    m.set(to, (m.get(to) || 0) + 1);
  };

  const deals = db.prepare(`
    SELECT d.id, d.stage FROM deals d
    WHERE EXISTS (SELECT 1 FROM touchpoints t WHERE t.deal_id = d.id)
  `).all() as { id: string; stage: string }[];

  const channelSet = new Set<string>();
  for (const d of deals) {
    const tps = getTouchpointsForDeal(d.id) as { channel: string; occurred_at: number }[];
    if (tps.length === 0) continue;
    tps.sort((a, b) => a.occurred_at - b.occurred_at);
    addEdge("start", tps[0].channel);
    channelSet.add(tps[0].channel);
    for (let i = 1; i < tps.length; i++) {
      addEdge(tps[i - 1].channel, tps[i].channel);
      channelSet.add(tps[i].channel);
    }
    const outcome = ["closed-won", "won"].includes(d.stage) ? "won" : "lost";
    addEdge(tps[tps.length - 1].channel, outcome);
  }

  return { transitions, channels: Array.from(channelSet) };
}

/**
 * Absorbing-state probability of reaching "won" from "start" under the
 * current transition graph. Computed by iterative substitution (the
 * transient-state equations converge in ~20 iterations for typical graphs).
 */
function absorbingWinProbability(
  transitions: Map<string, Map<string, number>>,
): number {
  // Normalize each row into probabilities.
  const rowSums = new Map<string, number>();
  for (const [from, m] of transitions) {
    let s = 0;
    for (const v of m.values()) s += v;
    rowSums.set(from, s);
  }
  const prob = (from: string, to: string): number => {
    const m = transitions.get(from);
    const s = rowSums.get(from) || 1;
    return m ? (m.get(to) || 0) / s : 0;
  };

  // Collect transient states (everything except won/lost).
  const states = Array.from(transitions.keys()).filter((s) => s !== "won" && s !== "lost");

  // Iterate: p(s) = sum over next states of prob(s, next) * p(next).
  // p("won") = 1, p("lost") = 0.
  let p = new Map<string, number>();
  for (const s of states) p.set(s, 0.5);
  for (let iter = 0; iter < 50; iter++) {
    const next = new Map<string, number>();
    let maxDelta = 0;
    for (const s of states) {
      let val = 0;
      const m = transitions.get(s)!;
      for (const [to, _] of m) {
        const pv = to === "won" ? 1 : to === "lost" ? 0 : p.get(to) ?? 0;
        val += prob(s, to) * pv;
      }
      next.set(s, val);
      maxDelta = Math.max(maxDelta, Math.abs(val - (p.get(s) ?? 0)));
    }
    p = next;
    if (maxDelta < 1e-6) break;
  }
  return p.get("start") ?? 0;
}

/**
 * Markov removal-effect credit per channel. For each channel c, remove c
 * from the graph (reroute its inbound edges to its outbound distribution),
 * recompute P(win), and credit(c) = total × (1 − P(win|¬c) / P(win|full)).
 *
 * Returns absolute credit shares per channel (sums to ~1.0). Falls back to
 * the legacy per-channel conversion-rate prior when the graph is degenerate
 * (no won deals, or fewer than 2 channels).
 */
function markovRemovalEffectCredits(
  tps: { channel: string; occurred_at: number }[],
  dealValue: number,
): Map<string, number> {
  const { transitions, channels } = buildMarkovGraph();
  const pFull = absorbingWinProbability(transitions);

  const credits = new Map<string, number>();

  if (pFull <= 0 || channels.length < 2) {
    // Degenerate — fall back to the legacy channel-rate prior on this deal's
    // actual touchpoints so the model still returns a usable allocation.
    const rates = getConversionRateByChannel();
    const mean = Object.values(rates).reduce((s, r) => s + r, 0) / Math.max(1, Object.keys(rates).length);
    const weights = tps.map((t) => Math.max(0.1, rates[t.channel] || mean));
    const wsum = weights.reduce((s, w) => s + w, 0) || 1;
    for (let i = 0; i < tps.length; i++) {
      const c = tps[i].channel;
      credits.set(c, (credits.get(c) || 0) + (weights[i] / wsum));
    }
    return credits;
  }

  for (const c of channels) {
    // Remove channel c: copy transitions, drop c as a node, reroute its
    // inbound edges directly to its outbound distribution.
    const removed = new Map<string, Map<string, number>>();
    for (const [from, m] of transitions) {
      if (from === c) continue;
      const nm = new Map<string, number>();
      for (const [to, v] of m) {
        if (to === c) {
          // Reroute: distribute c's outbound weights to this edge.
          const cOut = transitions.get(c);
          if (cOut) {
            let cOutSum = 0;
            for (const vv of cOut.values()) cOutSum += vv;
            for (const [cTo, cV] of cOut) {
              nm.set(cTo, (nm.get(cTo) || 0) + (v * cV) / (cOutSum || 1));
            }
          }
        } else {
          nm.set(to, v);
        }
      }
      removed.set(from, nm);
    }
    const pRemoved = absorbingWinProbability(removed);
    const removalEffect = 1 - pRemoved / pFull;
    credits.set(c, Math.max(0, removalEffect));
  }

  // Normalize removal effects across the channels that actually appear in
  // this deal's path (others get 0). If all removal effects are 0 (every
  // channel is interchangeable), fall back to linear within the deal.
  const dealChannels = new Set(tps.map((t) => t.channel));
  let sum = 0;
  for (const c of dealChannels) sum += credits.get(c) || 0;
  if (sum <= 0) {
    const w = 1 / tps.length;
    credits.clear();
    for (const t of tps) credits.set(t.channel, (credits.get(t.channel) || 0) + w);
    return credits;
  }
  for (const c of credits.keys()) {
    if (!dealChannels.has(c)) {
      credits.set(c, 0);
    } else {
      credits.set(c, (credits.get(c) || 0) / sum);
    }
  }
  return credits;
}

