case "data_driven": {
  // Markov removal-effect: real multi-touch attribution on the channel
  // transition graph. The credit map is per-channel share of the deal's
  // total value; convert to per-touchpoint weights so the existing
  // channel-aggregation logic below handles the rollup.
  const shares = markovRemovalEffectCredits(
    tps as { channel: string; occurred_at: number }[],
    value,
  );
  // Distribute each channel's share equally across that channel's
  // touchpoints within this deal (a channel touched twice gets its share
  // split in two).
  const counts = new Map<string, number>();
  for (const t of tps) counts.set(t.channel, (counts.get(t.channel) || 0) + 1);
  weights = tps.map((t) => {
    const share = shares.get(t.channel) || 0;
    return share / Math.max(1, counts.get(t.channel) || 1);
  });
  const wsum = weights.reduce((s, w) => s + w, 0);
  if (wsum > 0) weights = weights.map((w) => w / wsum);
  break;
}

