// 3. No fabricated metrics (flag numbers not in the hub data).
// Numbers are normalized to floats before comparison so "$50,000", "50k",
// "fifty thousand", and "50000" all match a hub metric of 50000. Tolerance
// is ±2% to absorb rounding/reformatting. Percentages are no longer skipped.
const fabricatedMetrics: string[] = [];
if (hubMetrics) {
  const hubNums = Object.values(hubMetrics)
    .map((v) => normalizeNumber(String(v)))
    .filter((n): n is number => n !== null);
  const numPatterns = text.match(/\$[\d,.]+\s*(?:k|m|thousand|million)?|\b\d[\d,]*\.?\d*\s*(?:%|k|m|thousand|million)?\b|\b(?:fifty|one hundred|two hundred|five hundred)\s+thousand\b/gi) || [];
  const seen = new Set<number>();
  for (const pattern of numPatterns) {
    const num = normalizeNumber(pattern);
    if (num === null || seen.has(num)) continue;
    seen.add(num);
    const matchesHub = hubNums.some((hn) => hn > 0 && Math.abs(num - hn) / hn <= 0.02);
    if (!matchesHub && num > 10) {
      fabricatedMetrics.push(pattern.trim());
    }
  }
  if (fabricatedMetrics.length > 0) {
    score -= fabricatedMetrics.length * 15;
    issues.push(`Potential fabricated metrics (not in hub data): ${fabricatedMetrics.join(", ")}. BAZ doctrine: proof beats promises — no fabricated numbers.`);
  }
}

