export interface QualityResult {
  passed: boolean;
  score: number;          // 0-100
  grade: string;          // A+, A, B, C, D, F
  issues: string[];       // specific problems found
  cleanedText: string;    // the text with hype words flagged
  metrics: {
    hypeWordCount: number;
    revenueAnchored: boolean;
    fabricatedMetrics: string[];
    proofDensity: number;  // 0-1 (claims with proof / total claims)
    // Four U's scoring (looted from Kai CMO Harness)
    fourUs: {
      usefulness: number;     // 0-1
      urgency: number;        // 0-1
      uniqueness: number;     // 0-1
      ultraSpecificity: number; // 0-1
      average: number;        // 0-1
    };
    // Hallucination detection (looted from DM Pro eval/QA)
    hallucinationFlags: string[];
    suspiciousUrls: string[];
    unsubstantiatedClaims: number;
    /** Which scorer produced the sub-scores: "llm" (calibrated judge) or "regex" (fallback). */
    scorer: "llm" | "regex";
  };
}

/**
 * Normalize a number-like string to a float, handling $, commas, %, k/m,
 * and word forms ("fifty thousand", "2.5m"). Returns null if not parseable.
 * Fixes the prior exact-integer-equality bug that missed every reformatted
 * number and skipped percentages entirely.
 */
function normalizeNumber(s: string): number | null {
  const lower = s.toLowerCase().replace(/[,$%\s]/g, "");
  // word thousands
  const wordMatch = lower.match(/^(\d+(?:\.\d+)?)?(fifty|one|two|three|four|five|six|seven|eight|nine)?hundredthousand$/);
  if (wordMatch) {
    const base = wordMatch[1] ? parseFloat(wordMatch[1]) : { fifty: 50, one: 1, two: 2, three: 3, four: 4, five: 5, six: 6, seven: 7, eight: 8, nine: 9 }[wordMatch[2]] || 1;
    return base * 100000;
  }
  let m = lower.match(/^(\d+(?:\.\d+)?)(k|m|thousand|million)?$/);
  if (m) {
    const n = parseFloat(m[1]);
    const unit = m[2];
    if (unit === "k" || unit === "thousand") return n * 1000;
    if (unit === "m" || unit === "million") return n * 1_000_000;
    return n;
  }
  return null;
}

interface JudgeScores {
  usefulness: number;
  urgency: number;
  uniqueness: number;
  specificity: number;
  proof: number;
  unsubstantiated_claims: number;
  fabricated_numbers: string[];
  reason: string;
}

