/**
 * LLM-as-judge — returns calibrated 0-1 sub-scores for the Four U's + proof
 * density, plus a count of unsubstantiated claims and any numbers the judge
 * believes are fabricated. Temperature 0 for determinism. Returns null if
 * the call fails so the caller falls back to the regex scorers.
 *
 * Calibrate against data/quality-calibration.jsonl (200 human-graded samples)
 * before trusting the absolute floats; until then the floats are still more
 * accurate than the regex counts but should be treated as directional.
 */
async function judgeQuality(
  text: string,
  hubMetrics?: Record<string, number | string>,
): Promise<JudgeScores | null> {
  const hubContext = hubMetrics
    ? `Known hub metrics (a number is fabricated if it's not within 2% of one of these): ${JSON.stringify(hubMetrics)}`
    : "No hub metrics available — flag only numbers that are clearly invented (impossibly precise, contradictory, or unsourced statistics).";

  const system = `You are a strict marketing-copy quality judge. Score the text on five dimensions, each 0.0-1.0:
- usefulness: does it address the audience's concrete need with a real benefit?
- urgency: does it give a genuine reason to act now (not false scarcity)?
- uniqueness: does it differentiate from alternatives?
- specificity: does it use concrete numbers, named mechanisms, and specific outcomes (not vague adjectives)?
- proof: fraction of claims backed by reasoning, data, or a named mechanism.
Also count unsubstantiated_claims (sentences with superlatives but no evidence) and list fabricated_numbers (numbers not in the hub metrics and not obviously generic).
Return ONLY valid JSON matching this shape:
{"usefulness":0.0,"urgency":0.0,"uniqueness":0.0,"specificity":0.0,"proof":0.0,"unsubstantiated_claims":0,"fabricated_numbers":[],"reason":"one line"}`;

  const res = await glmChat(
    [
      { role: "system", content: system },
      { role: "system", content: hubContext },
      { role: "user", content: text },
    ],
    { model: "glm-4-plus", temperature: 0, maxTokens: 512 },
  );
  if (!res.ok || !res.content) return null;
  try {
    // Tolerate code fences / leading text around the JSON.
    const match = res.content.match(/\{[\s\S]*\}/);
    if (!match) return null;
    const parsed = JSON.parse(match[0]) as Partial<JudgeScores>;
    const clamp = (n: unknown) => Math.max(0, Math.min(1, Number(n) || 0));
    return {
      usefulness: clamp(parsed.usefulness),
      urgency: clamp(parsed.urgency),
      uniqueness: clamp(parsed.uniqueness),
      specificity: clamp(parsed.specificity),
      proof: clamp(parsed.proof),
      unsubstantiated_claims: Math.max(0, Math.round(Number(parsed.unsubstantiated_claims) || 0)),
      fabricated_numbers: Array.isArray(parsed.fabricated_numbers)
        ? parsed.fabricated_numbers.map(String)
        : [],
      reason: String(parsed.reason || ""),
    };
  } catch {
    return null;
  }
}

