export interface CrossReference {
  source: string;      // which system
  type: string;        // what kind of reference
  title: string;       // display title
  description: string; // why it matters
  href: string;        // link to the feature
  priority: number;    // 0-1, higher = more relevant now
}

/**
 * Map an input value to a 0-100 score by its rank within a reference ladder
 * of 10 thresholds (the 10th, 20th, … 100th percentile anchors). Replaces
 * the prior magic-base/divisor formulas whose "80" meant an invented number;
 * now "80" means "above the 8th rung of the ladder". The ladders are tuned
 * to typical hub scales and can be replaced by the hub's own rolling 90th
 * percentile once enough history accumulates. See HEURISTICS_AUDIT.md #7.
 */
function percentileScore(value: number, ladder: number[]): number {
  if (ladder.length === 0) return 0;
  if (value <= 0) return 0;
  for (let i = 0; i < ladder.length; i++) {
    if (value < ladder[i]) {
      const lo = i === 0 ? 0 : ladder[i - 1];
      const t = (value - lo) / (ladder[i] - lo);
      return Math.round((i + t) * 10);
    }
  }
  return 100;
}

