input.newString:
/**
 * Published organic CTR curve by ranking position (desktop, aggregated from
 * Advanced Web Ranking / Ahrefs studies). Index 0 = position 1. This is
 * doctrine (citable industry data), not a magic multiplier. Used to turn
 * search volume into estimated clicks so opportunity scores reflect real
 * traffic, not a toy closeness factor. See docs/HEURISTICS_AUDIT.md #9.
 */
const ORGANIC_CTR_BY_POSITION = [
  0.27, 0.15, 0.11, 0.075, 0.055,
  0.04, 0.03, 0.025, 0.02, 0.016,
  0.012, 0.01, 0.008, 0.006, 0.005,
  0.004, 0.0035, 0.003, 0.0025, 0.002,
];

/** Estimated organic clicks/month for a keyword at a given position. */
export function estimatedClicks(volume: number, position: number): number {
  if (position <= 0 || volume <= 0) return 0;
  const idx = Math.min(ORGANIC_CTR_BY_POSITION.length - 1, Math.max(0, Math.floor(position) - 1));
  // Beyond the tabulated range, CTR decays roughly geometrically.
  const ctr = position > ORGANIC_CTR_BY_POSITION.length
    ? ORGANIC_CTR_BY_POSITION[ORGANIC_CTR_BY_POSITION.length - 1] * Math.pow(0.7, position - ORGANIC_CTR_BY_POSITION.length)
    : ORGANIC_CTR_BY_POSITION[idx];
  return Math.round(volume * ctr);
}

/**
 * Keyword difficulty. NOTE: the prior formula was a "toy" that derived
 * difficulty from the *current ranking position* (circular — difficulty
 * shouldn't depend on where you happen to rank). Difficulty should come
 * from the SEO data provider's domain-authority / backlink metric. This
 * wrapper now expects an external `domainDifficulty` and only falls back to
 * the toy formula when none is supplied (labeled uncalibrated).
 */
export function keywordDifficulty(volume: number, position: number, domainDifficulty?: number): number {
  if (typeof domainDifficulty === "number" && domainDifficulty > 0) {
    return Math.min(100, Math.max(0, Math.round(domainDifficulty)));
  }
  // Uncalibrated fallback — do not trust for decisions.
  const posScore = Math.min(60, Math.max(0, position * 6));
  const volScore = Math.min(40, Math.log10(Math.max(1, volume)) * 10);
  return Math.min(100, Math.round(posScore + volScore - 10));
}

/**
 * Keyword opportunity score = estimated clicks (from the published CTR
 * curve) ÷ difficulty, scaled. Replaces the toy `log10(volume)*30 /
 * max(5,difficulty) * closeness` formula with a traffic-based number so the
 * score ranks keywords by actual reachable clicks. The `commercialIntent`
 * weight (0-1) lets transactional keywords outrank informational ones at
 * the same volume.
 */
export function keywordOpportunityScore(
  volume: number,
  difficulty: number,
  position: number,
  commercialIntent: number = 0.5,
): number {
  const clicks = estimatedClicks(volume, position);
  const diff = Math.max(1, difficulty);
  const raw = (clicks / diff) * Math.max(0.1, Math.min(1, commercialIntent));
  return Math.round(raw * 10) / 10;
}

