input.newString:
/**
 * Score every article's relevance against the workspace's positioning,
 * voice, tribe, and personas using TF-IDF cosine similarity. Replaces the
 * prior substring hit-count (`30 + hits*12 + featured?10:0`) which missed
 * every morphological variant and used invented weights. See
 * docs/HEURISTICS_AUDIT.md #10. The `is_featured` flag is kept as a
 * separate column, not baked into the score.
 */
export function scoreRelevance(): number {
  const articles = db.prepare(`SELECT * FROM wire_articles`).all() as Record<string, unknown>[];
  const positioning = (db.prepare(`SELECT value FROM settings WHERE key = 'smallest_true_thing'`).get() as { value: string } | undefined)?.value || "";
  const change = (db.prepare(`SELECT value FROM settings WHERE key = 'change_we_lead'`).get() as { value: string } | undefined)?.value || "";
  const tribe = (db.prepare(`SELECT value FROM settings WHERE key = 'tribe'`).get() as { value: string } | undefined)?.value || "";
  const wordsUse = (db.prepare(`SELECT value FROM settings WHERE key = 'words_use'`).get() as { value: string } | undefined)?.value || "";
  const ctx = `${positioning} ${change} ${tribe} ${wordsUse}`;

  // Build the corpus = context + all article texts. IDF is computed over the
  // article corpus so terms common to many articles get downweighted.
  const docs = articles.map((a) => `${a.title} ${a.summary} ${a.nova_take}`);
  const ctxTokens = tokenize(ctx);
  const articleTokens = docs.map(tokenize);

  // Document frequency for IDF (count articles containing each term).
  const df = new Map<string, number>();
  for (const toks of articleTokens) {
    for (const t of new Set(toks)) df.set(t, (df.get(t) || 0) + 1);
  }
  const N = Math.max(1, articleTokens.length);
  const idf = (term: string) => Math.log((N + 1) / (1 + (df.get(term) || 0)) + 1);

  // Context vector (TF-IDF over the workspace terms).
  const ctxVec = tfidfVector(ctxTokens, idf);
  const ctxNorm = norm(ctxVec);

  let updated = 0;
  for (let i = 0; i < articles.length; i++) {
    const a = articles[i];
    const artVec = tfidfVector(articleTokens[i], idf);
    const artNorm = norm(artVec);
    let sim = 0;
    if (ctxNorm > 0 && artNorm > 0) {
      for (const [term, w] of ctxVec) {
        const aw = artVec.get(term);
        if (aw) sim += w * aw;
      }
      sim = sim / (ctxNorm * artNorm);
    }
    // Scale cosine (0-1) to 0-100.
    const rel = Math.round(Math.max(0, Math.min(1, sim)) * 100);
    db.prepare(`UPDATE wire_articles SET relevance = ? WHERE id = ?`).run(rel, a.id);
    updated++;
  }
  return updated;
}

function tokenize(s: string): string[] {
  return String(s || "").toLowerCase().split(/\W+/).filter((w) => w.length > 2);
}

function tfidfVector(tokens: string[], idf: (t: string) => number): Map<string, number> {
  const tf = new Map<string, number>();
  for (const t of tokens) tf.set(t, (tf.get(t) || 0) + 1);
  const vec = new Map<string, number>();
  for (const [t, count] of tf) vec.set(t, (count / tokens.length) * idf(t));
  return vec;
}

function norm(v: Map<string, number>): number {
  let s = 0;
  for (const w of v.values()) s += w * w;
  return Math.sqrt(s);
}

input.oldString:
/**
 * Score every article's relevance against the workspace's positioning,
 * voice, tribe, and personas. Cheap heuristic, but it makes the feed
 * feel alive instead of generic.
 */
export function scoreRelevance(): number {
  // Refresh all relevance scores
  const articles = db.prepare(`SELECT * FROM wire_articles`).all() as Record<string, unknown>[];
  const positioning =
    (db.prepare(`SELECT value FROM settings WHERE key = 'smallest_true_thing'`).get() as { value: string } | undefined)
      ?.value || "";
  const change =
    (db.prepare(`SELECT value FROM settings WHERE key = 'change_we_lead'`).get() as { value: string } | undefined)?.value ||
    "";
  const tribe =
    (db.prepare(`SELECT value FROM settings WHERE key = 'tribe'`).get() as { value: string } | undefined)?.value || "";
  const wordsUse =
    (db.prepare(`SELECT value FROM settings WHERE key = 'words_use'`).get() as { value: string } | undefined)?.value || "";
  const ctx = `${positioning} ${change} ${tribe} ${wordsUse}`.toLowerCase();
  const ctxTerms = ctx.split(/\W+/).filter((w: string) => w.length > 3);

  let updated = 0;
  for (const a of articles) {
    const text = `${a.title} ${a.summary} ${a.nova_take}`.toLowerCase();
    const hits = ctxTerms.reduce((s: number, t: string) => s + (text.includes(t) ? 1 : 0), 0);
    const rel = Math.min(100, 30 + hits * 12 + (a.is_featured ? 10 : 0));
    db.prepare(`UPDATE wire_articles SET relevance = ? WHERE id = ?`).run(rel, a.id);
    updated++;
  }
  return updated;
}

