/**
 * Run Sabri's audit on a set of pages.
 *
 * The seven boolean checks are doctrinal (named master, cited in the file
 * header) and are kept as a checklist. The score is now a simple count of
 * checks passed (each worth 100/7 ≈ 14.3 points) rather than the prior
 * invented weights (CTA=25, social proof=20, hero=15…). Sabri says CTA is
 * the #1 lever but doesn't say "exactly 25 points" — and without per-page
 * conversion data we can't fit the weights, so equal weighting is the
 * honest default. Once conversion data is wired, the weights can be fit by
 * regressing the booleans against conversion rate. See HEURISTICS_AUDIT.md #11.
 */
export function sabriAudit(
  pages: Array<{ name: string; url: string; html?: string }>,
): PageAudit[] {
  const CHECK_COUNT = 7;
  return pages.map((p) => {
    const a = TEMPLATE(p.name, p.url);
    const html = (p.html || "").toLowerCase();
    a.has_hero = /<h1[\s>]/.test(html);
    a.has_clear_cta = /(start free|get started|book|sign up|try|buy|join|subscribe)/i.test(html);
    a.has_social_proof = /(customer|testimonial|review|trusted by|users|companies|\d+,\d+)/i.test(html);
    a.has_risk_reversal = /(money.back|free trial|cancel anytime|30.day|guarantee|ris.k.free)/i.test(html);
    a.has_urgency = /(today|now|limited|ends|deadline|expires|hurry)/i.test(html);
    a.has_specificity = /\d+%|\d+,\d+|\$\d+|\d+ (days|hours|min)/i.test(html);
    a.has_one_offer = (html.match(/<button|<a [^>]*cta/gi) || []).length <= 3;

    const passed =
      (a.has_hero ? 1 : 0) +
      (a.has_clear_cta ? 1 : 0) +
      (a.has_social_proof ? 1 : 0) +
      (a.has_risk_reversal ? 1 : 0) +
      (a.has_urgency ? 1 : 0) +
      (a.has_specificity ? 1 : 0) +
      (a.has_one_offer ? 1 : 0);
    a.score = Math.round((passed / CHECK_COUNT) * 100);
    a.grade = a.score >= 90 ? "A" : a.score >= 75 ? "B" : a.score >= 60 ? "C" : a.score >= 40 ? "D" : "F";
    a.calibration = "checklist-unweighted";

    if (!a.has_hero) a.issues.push("No clear H1. The hero is the only thing most visitors read.");
    if (!a.has_clear_cta)
      a.issues.push("No CTA visible. Every page needs ONE clear call-to-action.");
    if (!a.has_social_proof)
      a.issues.push("Missing social proof. Specificity beats quantity ('2,847 users' > 'thousands').");
    if (!a.has_risk_reversal)
      a.issues.push("No risk reversal. Money-back, free trial, or cancel-anytime removes the objection.");
    if (!a.has_urgency) a.issues.push("No urgency. Only if true — false urgency destroys trust.");
    if (!a.has_specificity) a.issues.push("Vague copy. Numbers beat adjectives.");
    if (!a.has_one_offer) a.issues.push("Too many CTAs. One page, one offer, one action.");

    a.sabri_take = sabriVerdict(a);
    return a;
  });
}

