import type { AuditCheck, AdsHealthReport, PlatformScore, BusinessType } from "./types";
import {
  buildGoogleChecks,
  buildMetaChecks,
  buildLinkedInChecks,
  buildTikTokChecks,
  buildMicrosoftChecks,
  buildAppleChecks,
  buildAmazonChecks,
  buildCrossPlatformChecks,
} from "./checks/platform-checks";
import { calculateWeightedScore, scoreToGrade, summarizePlatforms, prioritizeFindings, generateQuickWins, detectBusinessType } from "./scoring";

export async function runAudit(input: {
  platforms: string[];
  businessType?: string;
  industry?: string;
  monthlySpend?: number;
  data: Record<string, Record<string, unknown>>;
}): Promise<AdsHealthReport> {

input.newString:
  return {
    ads_health_score: overallScore,
    grade: scoreToGrade(overallScore),
    audit_date: new Date().toISOString().split("T")[0] || "",
    platforms,
    top_findings: topFindings,
    quick_wins: quickWins,
    budget_rec: generateBudgetRec(businessType, input.monthlySpend || 5000, input.data.cross?.channelRoas as Record<string, number> | undefined),
    creative_rec: generateCreativeRec(businessType, input.platforms),
  };
}

/**
 * Budget recommendation. The 70/20/10 split (proven/scaling/testing) is
 * doctrine and kept as the default. The channel *assignment* was a fixed
 * per-business-type table that ignored the hub's own channel performance.
 * Now, when per-channel ROAS is supplied (via cross.channelRoas), the
 * highest-ROAS channel gets `proven`, second gets `scaling`, and new/experimental
 * channels get `testing` — falling back to the per-type table only when fewer
 * than 3 channels have ROAS data. See docs/HEURISTICS_AUDIT.md #12.
 */
function generateBudgetRec(
  businessType: BusinessType,
  monthlySpend: number,
  channelRoas?: Record<string, number>,
): { monthly_budget: number; allocation: Record<string, number>; rationale: string } {
  const proven = Math.round(monthlySpend * 0.7);
  const scaling = Math.round(monthlySpend * 0.2);
  const testing = Math.round(monthlySpend * 0.1);
  const allocation: Record<string, number> = {};

  // If we have ROAS for ≥3 channels, assign by performance instead of business type.
  if (channelRoas && Object.keys(channelRoas).length >= 3) {
    const ranked = Object.entries(channelRoas)
      .filter(([, r]) => typeof r === "number" && r > 0)
      .sort(([, a], [, b]) => b - a);
    if (ranked.length >= 3) {
