/**
 * Extract key insights from a long-form piece.
 *
 * Default path: an LLM call (via glmChat) that ranks chunks by insight
 * density and returns the top N as a JSON array — far better than positional
 * chunking. Falls back to the prior 3-sentence chunking (kept, labeled) when
 * GLM is unavailable so the function always returns something. See
 * docs/HEURISTICS_AUDIT.md #13.
 */
export async function extractInsights(rawContent: string, maxInsights = 7): Promise<string[]> {
  if (isGLMAvailable()) {
    const res = await glmChat(
      [
        {
          role: "system",
          content: `You extract standalone insights from long-form content. Return ONLY a JSON array of strings, the top ${maxInsights} insights ranked by insight density (specificity + non-obviousness + reusability). Each string should be a self-contained insight (1-3 sentences). No commentary, no wrapping object — just the array.`,
        },
        { role: "user", content: rawContent.slice(0, 12000) },
      ],
      { model: "glm-4-plus", temperature: 0, maxTokens: 2048 },
    );
    if (res.ok && res.content) {
      try {
        const match = res.content.match(/\[[\s\S]*\]/);
        if (match) {
          const arr = JSON.parse(match[0]) as unknown;
          if (Array.isArray(arr)) {
            return arr
              .map((x) => String(x).trim())
              .filter((s) => s.length > 20 && s.length < 600)
              .slice(0, maxInsights);
          }
        }
      } catch {
        // fall through to chunking
      }
    }
  }

  // Fallback: positional 3-sentence chunking. Not salience-ranked.
  return extractInsightsChunked(rawContent, maxInsights);
}

/** Synchronous chunking fallback (the prior heuristic). Not ranked. */
function extractInsightsChunked(rawContent: string, maxInsights = 7): string[] {
  const sentences = rawContent
    .replace(/\n+/g, " ")
    .split(/(?<=[.!?])\s+/)
    .map((s) => s.trim())
    .filter((s) => s.length > 20 && s.length < 400);

  if (!sentences.length) return [];

  const insights: string[] = [];
  const chunkSize = 3;
  for (let i = 0; i < sentences.length && insights.length < maxInsights; i += chunkSize) {
    const chunk = sentences.slice(i, i + chunkSize).join(" ");
    if (chunk.length > 30 && chunk.length < 600) insights.push(chunk);
  }
  return insights;
}

