input.newString:
import { NextRequest } from "next/server";
import { json, err, readJson } from "@/lib/api-helpers";
import { requireUser } from "@/lib/admin";
import { db, uid, now } from "@/lib/db";
import { glmChat, isGLMAvailable } from "@/lib/glm";

export const dynamic = "force-dynamic";

interface GraduatedBrief {
  insight: string;
  promise: string;
  proof: string;
  call_to_action: string;
}

/**
 * Use the LLM to extract a structured brief (insight / promise / proof /
 * CTA) from the idea's free-text description. Falls back to the prior
 * first-sentence split when GLM is unavailable. See HEURISTICS_AUDIT.md #15.
 */
async function graduateDescription(
  idea: Record<string, unknown>,
): Promise<GraduatedBrief> {
  const desc = String(idea.description || "").trim();
  const fallback: GraduatedBrief = {
    insight: desc.split(/[.!?\n]/)[0] || desc || "The market context that makes this timely.",
    promise: desc.slice((desc.split(/[.!?\n]/)[0] || desc).length).trim() || desc || "A clear promise to the audience.",
    proof: String(idea.experiment || "Run a 7-day pilot; track engagement + conversions."),
    call_to_action: "Click / Sign up / Reply — one action that proves the message landed.",
  };

  if (!isGLMAvailable() || !desc) return fallback;

  const res = await glmChat(
    [
      {
        role: "system",
        content: `You turn a marketing idea into a campaign brief. Return ONLY JSON: {"insight":"...","promise":"...","proof":"...","call_to_action":"..."}. Each field one sentence. insight = the market context that makes this timely; promise = the specific outcome offered; proof = how we'll validate it; call_to_action = the single action the audience takes.`,
      },
      {
        role: "user",
        content: `Title: ${idea.title}\nDescription: ${desc}\nWhy now: ${idea.why_now || ""}\nAudience: ${idea.audience || ""}`,
      },
    ],
    { model: "glm-4-plus", temperature: 0.4, maxTokens: 512 },
  );
  if (!res.ok || !res.content) return fallback;
  try {
    const match = res.content.match(/\{[\s\S]*\}/);
    if (!match) return fallback;
    const p = JSON.parse(match[0]) as Partial<GraduatedBrief>;
    return {
      insight: String(p.insight || fallback.insight),
      promise: String(p.promise || fallback.promise),
      proof: String(p.proof || fallback.proof),
      call_to_action: String(p.call_to_action || fallback.call_to_action),
    };
  } catch {
    return fallback;
  }
}

/**
 * Graduate an idea to a Campaign Brief.
 *
 * Pulls the idea's title/description/audience/why_now into the brief shape
 * (structured by the LLM when available), marks the idea as "sprouting" so
 * it shows up the pipeline column, and returns the new brief id.
 */
export async function POST(req: NextRequest) {
  const guard = requireUser();
  if (guard instanceof Response) return guard;

  const body = await readJson<Record<string, unknown>>(req);
  if (!body?.ideaId) return err("ideaId required");

  const idea = db.prepare(`SELECT * FROM ideas WHERE id = ?`).get(body.ideaId) as
    Record<string, unknown> | undefined;
  if (!idea) return err("Idea not found", 404);

  const id = uid("cb_");
  const t = now();

  const brief = await graduateDescription(idea);

  db.prepare(
    `
    INSERT INTO campaign_briefs
      (id, workspace, title, objective, target_audience, insight, promise, proof, call_to_action, success_metric, channels, notes, created_at, updated_at)
    VALUES (?, 'default', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `,
  ).run(
    id,
    `From idea: ${idea.title}`,
    idea.why_now || "Drive a meaningful lift in the target metric.",
    idea.audience || "The primary persona.",
    brief.insight,
    brief.promise,
    brief.proof,
    brief.call_to_action,
    "Track the lift over a 7-day window vs. the prior week.",
    JSON.stringify([]),
    `Graduated from Idea Board${idea.category ? ` · ${idea.category}` : ""}`,
    t,
    t,
  );

  // Mark idea as sprouting (in flight toward a campaign)
  db.prepare(`UPDATE ideas SET status = 'sprouting', updated_at = ? WHERE id = ?`).run(
    t,
    body.ideaId,
  );

  return json({ ok: true, briefId: id, ideaId: body.ideaId }, 201);
}

