// ⚠️ DEMO DATA — synthetic generators for dashboard previews.
// These functions produce deterministic-but-fake time series, channel
// breakdowns, and funnels. They do NOT measure anything. Shipping them in a
// production analytics dashboard contradicts the BAZ doctrine (proof beats
// promises) and the hub's own fabricated-metric detector. Until real
// instrumentation (revenue_events / touchpoints / deals aggregated by day)
// is wired in, every consumer MUST label its chart "DEMO DATA".
// See docs/HEURISTICS_AUDIT.md #16.

export const IS_DEMO_DATA = true as const;

export function seeded(seed: number) {
  return () => {
    seed = (seed * 9301 + 49297) % 233280;
    return seed / 233280;
  };
}

export function trendSeries(
  days: number,
  base: number,
  variance: number,
  seed = 42,
): { date: string; value: number; isDemo: true }[] {
  const r = seeded(seed);
  const out: { date: string; value: number; isDemo: true }[] = [];
  const now = Date.now();
  for (let i = days - 1; i >= 0; i--) {
    const d = new Date(now - i * 86400000);
    const v = base + (r() - 0.5) * variance + Math.sin(i / 3) * variance * 0.3;
    out.push({ date: d.toISOString().slice(5, 10), value: Math.max(0, Math.round(v)), isDemo: true });
  }
  return out;
}

export function channelBreakdown(
  seed = 42,
): { name: string; value: number; color: string; isDemo: true }[] {
  const r = seeded(seed);
  const channels = [
    { name: "Organic", color: "#16a34a" },
    { name: "Paid", color: "var(--accent)" },
    { name: "Social", color: "#0ea5e9" },
    { name: "Email", color: "#f59e0b" },
    { name: "Direct", color: "#64748b" },
    { name: "Referral", color: "#ec4899" },
  ];
  const raw = channels.map((c) => ({ ...c, value: 800 + r() * 4000 }));
  const total = raw.reduce((s, x) => s + x.value, 0);
  return raw.map((c) => ({ ...c, value: Math.round((c.value / total) * 100), isDemo: true }));
}

export function funnel(
  stages: string[],
): { stage: string; count: number; rate: number; isDemo: true }[] {
  const r = seeded(7);
  const counts: number[] = [];
  let prev = 8000 + r() * 4000;
  for (let i = 0; i < stages.length; i++) {
    counts.push(Math.round(prev));
    prev = prev * (0.4 + r() * 0.4);
  }
  return stages.map((stage, i) => {
    const count = counts[i];
    const rate = i === 0 ? 100 : Math.round((count / counts[0]) * 100);
    return { stage, count, rate, isDemo: true };
  });
}

