export function getHotLeads(limit = 20): IntentScore[] {
  // Get contacts with recent signals
  const thirtyDaysAgo = now() - 30 * 24 * 60 * 60 * 1000;
  const contactIds = db.prepare(`
    SELECT DISTINCT contact_id FROM intent_signals WHERE timestamp > ? ORDER BY timestamp DESC LIMIT ?
  `).all(thirtyDaysAgo, limit * 3) as { contact_id: string }[];

  return contactIds
    .map((c) => scoreIntent(c.contact_id))
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
}

