 * measurement" primitive — bucket predicted scores into deciles, compare
 * average predicted vs average actual label per bucket.
 */
export function calibrate(scores: number[], labels: number[]): CalibrationResult {
  const n = scores.length;
  if (n === 0) return { buckets: [], auc: 0.5, n: 0 };

  const rows = scores.map((s, i) => ({ s, y: labels[i] })).sort((a, b) => a.s - b.s);
  const buckets: CalibrationBucket[] = [];
  const binSize = Math.max(1, Math.ceil(n / 10));
  for (let i = 0; i < n; i += binSize) {
    const slice = rows.slice(i, i + binSize);
    const avgScore = slice.reduce((s, r) => s + r.s, 0) / slice.length;
    const avgLabel = slice.reduce((s, r) => s + r.y, 0) / slice.length;
    const lo = (i / n).toFixed(1);
    const hi = (Math.min(n, i + binSize) / n).toFixed(1);
    buckets.push({ bin: `${lo}-${hi}`, avgScore, avgLabel, count: slice.length });
  }

  return { buckets, auc: auc(scores, labels), n };

